package com.pinova.api.controller;import com.pinova.api.request.*;import com.pinova.api.response.*;import com.pinova.api.web.CurrentAdminResolver;import com.pinova.common.api.ApiResponse;import com.pinova.service.AdminCategoryService;import com.pinova.service.command.SaveAdminCategoryCommand;import com.pinova.service.model.*;import jakarta.servlet.http.HttpServletRequest;import jakarta.validation.Valid;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController @RequestMapping("/admin/categories") public class AdminCategoryController{private final AdminCategoryService service;private final CurrentAdminResolver resolver;public AdminCategoryController(AdminCategoryService s,CurrentAdminResolver r){service=s;resolver=r;}
 @GetMapping public ApiResponse<List<AdminCategoryResponse>> list(HttpServletRequest r){return ApiResponse.success(service.list(resolver.requireCurrentAdmin(r)).stream().map(AdminCategoryController::response).toList());}
 @PostMapping public ApiResponse<AdminCategoryResponse> create(@Valid @RequestBody SaveAdminCategoryRequest b,HttpServletRequest r){return ApiResponse.success(response(service.save(command(resolver.requireCurrentAdmin(r),null,b))));}
 @PutMapping("/{id}") public ApiResponse<AdminCategoryResponse> update(@PathVariable Long id,@Valid @RequestBody SaveAdminCategoryRequest b,HttpServletRequest r){return ApiResponse.success(response(service.save(command(resolver.requireCurrentAdmin(r),id,b))));}
 @DeleteMapping("/{id}") public ApiResponse<Void> delete(@PathVariable Long id,@RequestParam int version,@Valid @RequestBody AdminReasonRequest b,HttpServletRequest r){service.delete(resolver.requireCurrentAdmin(r),id,version,b.reason());return ApiResponse.success(null);}
 private static SaveAdminCategoryCommand command(AuthenticatedAdminResult a,Long id,SaveAdminCategoryRequest b){return new SaveAdminCategoryCommand(a,id,b.parentId(),b.categoryCode(),b.name(),b.sortOrder(),b.iconUrl(),b.status(),b.version());}
 private static AdminCategoryResponse response(AdminCategoryResult c){return new AdminCategoryResponse(String.valueOf(c.id()),c.parentId()==null?null:String.valueOf(c.parentId()),c.categoryCode(),c.name(),c.level(),c.sortOrder(),c.iconUrl(),c.status(),c.version());}}
